// === Node 3: parse frontmatter + filter STALE projects (no vector DB) ===
// Runs once for ALL items. Robust to filesystem binary mode via getBinaryDataBuffer.
const items = $input.all();
const GLOBAL_STALE_DAYS = 5;
const today = new Date();
today.setHours(0, 0, 0, 0);
const toDate = (s) => { const d = new Date(String(s).trim()); return isNaN(d) ? null : d; };
const daysBetween = (a, b) => Math.floor((a - b) / 86400000);

// Minimal flat-YAML frontmatter parser. Handles `key: value` and `key: [a, b]`.
function parseFrontmatter(text) {
  const m = text.match(/^---\s*\n([\s\S]*?)\n---/);
  if (!m) return { fm: {}, body: text };
  const fm = {};
  for (const line of m[1].split(/\r?\n/)) {
    if (!line.trim() || line.trim().startsWith('#')) continue;
    const idx = line.indexOf(':');
    if (idx === -1) continue;
    let key = line.slice(0, idx).trim();
    let val = line.slice(idx + 1).trim();
    val = val.replace(/^["']|["']$/g, '');
    if (val.startsWith('[') && val.endsWith(']')) {
      val = val.slice(1, -1).split(',').map(s => s.trim()).filter(Boolean);
    }
    fm[key] = val;
  }
  return { fm, body: text.slice(m[0].length).trim() };
}

const stale = [];
for (let i = 0; i < items.length; i++) {
  const binMeta = items[i].binary && items[i].binary.data;
  if (!binMeta) continue;
  const buf = await this.helpers.getBinaryDataBuffer(i, 'data');
  const text = buf.toString('utf8');
  const { fm, body } = parseFrontmatter(text);
  if ((fm.type || '').toLowerCase() !== 'project') continue;        // projects only
  const status = (fm.status || '').toLowerCase();
  if (status === 'done') continue;                                  // ignore finished
  const last = toDate(fm.last_actionable_date);
  if (!last) continue;
  const threshold = parseInt(fm.stale_after_days, 10) || GLOBAL_STALE_DAYS;
  const age = daysBetween(today, last);
  if (age < threshold) continue;                                    // still warm

  // Keep payload small: trim the body to the most recent signal lines.
  const recent = body.split(/\r?\n/).filter(l => /log|^- |\[ \]|next/i.test(l)).slice(-8).join('\n');
  stale.push({
    title: fm.title || (binMeta.fileName || 'untitled').replace(/\.md$/, ''),
    status,
    priority: fm.priority || 'medium',
    deadline: fm.deadline || '',
    last_actionable_date: fm.last_actionable_date,
    days_stale: age,
    recent_notes: recent
  });
}

if (stale.length === 0) return [];   // nothing cold -> pipeline ends, no message sent
stale.sort((a, b) => b.days_stale - a.days_stale);

const SYSTEM_PROMPT = `You are the user's Agentic Second Brain — a terse, perceptive chief-of-staff that resurfaces neglected projects each morning over WhatsApp.
You receive JSON: today's date and an array of STALE projects (each with title, status, priority, deadline, days_stale, recent_notes).

RULES:
1. Pick the SINGLE highest-leverage project to nudge. Prefer: nearest deadline, then highest priority, then most days_stale. Mention at most one secondary project in a single short line.
2. Output ONLY the WhatsApp message body. No preamble, no explanation, no markdown code fences.
3. Format STRICTLY for a narrow phone screen using WhatsApp formatting: *bold* with single asterisks, _italics_ with underscores, and leading emojis as bullets. Keep total length under ~90 words. Short lines. Blank line between the three blocks.
4. Follow this exact 3-step flow:
   *🧊 THE HOOK* — name what went cold and for how many days (use days_stale).
   *🧠 THE CONTEXT* — paraphrase the recent_notes so they recognise where they left off.
   *✅ THE MICRO-ACTION* — ONE concrete task doable in 10 minutes. Make it absurdly low-friction.
5. Tone: warm, direct, zero guilt-tripping. Never invent facts not present in the notes.`;

const USER_CONTENT = JSON.stringify({
  today: today.toISOString().slice(0, 10),
  stale_projects: stale
}, null, 2);

return [{ json: { system: SYSTEM_PROMPT, user: USER_CONTENT, count: stale.length } }];
